Code.Terraform:
```hcl
resource "aws_sfn_state_machine" "<example_resource_name>" {
  name     = "<example_resource_name>"
  role_arn = "<example_resource_arn>"

  definition = jsonencode({
    Comment = "Example state machine"
    StartAt = "MyTask"
    States = {
      MyTask = {
        Type     = "Task"
        Resource = "arn:aws:states:::aws-sdk:secretsmanager:getSecretValue"
        Parameters = {
          SecretId = "<example_secret_name>"  # Reference secret by name, never hardcode value
        }
        End = true
      }
    }
  })
}
```
